import React from 'react';
import "./index.css"
import {  Layout } from 'antd';
const { Header, Content, Footer, Sider } = Layout;

const Layouts = () => {

  return (
    <Layout className='layout' >
      <Header
        style={{
          display: 'flex',
          alignItems: 'center',
          backgroundColor:'transparent',
          borderBottom:"1px slide red",
          border
        }}
      >

      </Header>
      <Content
        style={{
          padding: '0 50px',
          margin:"30px"
        }}
      >
        <Layout
          style={{
            height:"100%",
            padding: '24px 0',
            backgroundColor:"rgb(0,0,0,0.6)" ,
          }}
        >
          <Sider
            width={200}
            style={{
              backgroundColor:"transparent"
            }}
          >
          </Sider>
          <Content
            style={{
              padding: '0 24px',
              minHeight: 280,
            }}
          >
            Content
          </Content>
        </Layout>
      </Content>
      <Footer
        style={{
          textAlign: 'center',
          backgroundColor:'transparent'
        }}
      >
        Chat Room ©2023 Created by JY
      </Footer>
    </Layout>
  );
};
export default Layouts;
